class Solution(object):
    def largestSquareArea(self, bottomLeft, topRight):
        n = len(bottomLeft)
        best = 0
        for i in range(n):
            for j in range(i+1, n):
                # Intersection of rectangles i and j
                lx = max(bottomLeft[i][0], bottomLeft[j][0])
                ly = max(bottomLeft[i][1], bottomLeft[j][1])
                rx = min(topRight[i][0], topRight[j][0])
                ry = min(topRight[i][1], topRight[j][1])
                if rx > lx and ry > ly:
                    side = min(rx - lx, ry - ly)
                    best = max(best, side * side)
        return best
